---
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Icon } from "@/components/ui/icon"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  features: {
    title: string
    description: string
    icon: string
  }[]
}

const { class: className, title, description, buttons, features } = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="items-center gap-6 text-center">
    <div class="flex max-w-2xl flex-col items-center gap-4">
      <h2
        class="text-foreground text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      <p
        class="text-muted-foreground max-w-2xl text-lg leading-relaxed text-balance"
      >
        {description}
      </p>
    </div>
    {
      buttons?.length && (
        <div class="flex flex-wrap justify-center gap-3">
          {buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              variant={button.variant ?? (index === 0 ? "default" : "outline")}
              {...button}
            >
              {label}
            </Button>
          ))}
        </div>
      )
    }
  </SectionContainer>
  <SectionContainer>
    <div class="grid overflow-hidden rounded-xl sm:grid-cols-2 lg:grid-cols-3">
      {
        features.map((feature) => (
          <div class="group/feature hover:bg-accent/30 relative flex flex-col items-center gap-4 border-b p-7 text-center transition-colors sm:nth-last-[-n+2]:border-b-0 lg:nth-last-[-n+3]:border-b-0">
            <div class="bg-primary/10 text-primary ring-primary/15 flex size-10 items-center justify-center rounded-lg ring-1 transition-transform ring-inset group-hover/feature:scale-105">
              <Icon name={feature.icon} class="size-5" />
            </div>
            <h3 class="text-foreground text-base font-medium tracking-tight text-balance">
              {feature.title}
            </h3>
            <p class="text-muted-foreground text-sm leading-relaxed text-balance">
              {feature.description}
            </p>
          </div>
        ))
      }
    </div>
  </SectionContainer>
</Section>
